def smoothstep(e0: Float64, e1: Float64, x: Float64) -> Float64:
    var t = (x - e0) / (e1 - e0)
    if t < 0.0:
        t = 0.0
    if t > 1.0:
        t = 1.0
    return t * t * (3.0 - 2.0 * t)

