def quadratic_root_max(a: Float64, b: Float64, c: Float64) -> Float64:
    var disc = b * b - 4.0 * a * c
    var s = sqrt(disc)
    var r1 = (-b + s) / (2.0 * a)
    var r2 = (-b - s) / (2.0 * a)
    return r1 if r1 > r2 else r2

