def stddev4(a: Float64, b: Float64, c: Float64, d: Float64) -> Float64:
    var m = (a + b + c + d) / 4.0
    var s = (a - m) * (a - m) + (b - m) * (b - m) + (c - m) * (c - m) + (d - m) * (d - m)
    return sqrt(s / 4.0)

def trapezoid_integral(a: Float64, b: Float64) -> Float64:
    var n = 100
    var h = (b - a) / Float64(n)
    var s = 0.5 * (a * a + b * b)
    for i in range(1, n):
        var x = a + Float64(i) * h
        s += x * x
    return s * h

def bisection_sqrt2(target: Float64) -> Float64:
    var lo = 0.0
    var hi = target if target > 1.0 else 1.0
    for _i in range(60):
        var mid = 0.5 * (lo + hi)
        if mid * mid < target:
            lo = mid
        else:
            hi = mid
    return 0.5 * (lo + hi)

