def log_interp(x0: Float64, y0: Float64, x1: Float64, y1: Float64, x: Float64) -> Float64:
    var lx0 = log(x0)
    var lx1 = log(x1)
    var lx = log(x)
    var t = (lx - lx0) / (lx1 - lx0)
    return y0 + (y1 - y0) * t

